import{_ as e,o as a,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const f=JSON.parse('{"title":"鸟巢与水立方","description":"","frontmatter":{},"headers":[],"relativePath":"landmarks/niaochao.md","filePath":"landmarks/niaochao.md","lastUpdated":1784773307000}'),n={name:"landmarks/niaochao.md"};function o(d,t,s,i,h,g){return a(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="鸟巢与水立方" tabindex="-1">鸟巢与水立方 <a class="header-anchor" href="#鸟巢与水立方" aria-label="Permalink to &quot;鸟巢与水立方&quot;">​</a></h1><p><img src="https://images.unsplash.com/photo-rLCooDyRYqA?w=1200" alt="鸟巢"></p><blockquote><p>&quot;钢铁编织的鸟巢，见证了一个民族的腾飞。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>国家体育场&quot;鸟巢&quot;和国家游泳中心&quot;水立方&quot;位于北京奥林匹克公园中心区，是2008年北京奥运会的标志性建筑。鸟巢以其独特的钢结构外观闻名世界，水立方则以气泡状的ETFE膜结构成为建筑奇观。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">9:00-21:00（鸟巢），9:00-18:00（水立方）</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">鸟巢50元，水立方30元</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">2-3小时</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">四季皆宜</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁8号线奥体中心站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市朝阳区国家体育场南路1号（鸟巢），天辰东路11号（水立方）</td></tr></tbody></table><h2 id="鸟巢-国家体育场" tabindex="-1">鸟巢（国家体育场） <a class="header-anchor" href="#鸟巢-国家体育场" aria-label="Permalink to &quot;鸟巢（国家体育场）&quot;">​</a></h2><h3 id="建筑特色" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h3><p>鸟巢由瑞士建筑师赫尔佐格和德梅隆与中国建筑师合作设计，是世界上规模最大、技术含量最高的钢结构建筑之一。</p><h4 id="建筑参数" tabindex="-1">建筑参数 <a class="header-anchor" href="#建筑参数" aria-label="Permalink to &quot;建筑参数&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>占地面积</strong></td><td style="text-align:left;">21公顷</td></tr><tr><td style="text-align:left;"><strong>建筑面积</strong></td><td style="text-align:left;">25.8万平方米</td></tr><tr><td style="text-align:left;"><strong>座位数</strong></td><td style="text-align:left;">91000个</td></tr><tr><td style="text-align:left;"><strong>用钢量</strong></td><td style="text-align:left;">4.2万吨</td></tr><tr><td style="text-align:left;"><strong>高度</strong></td><td style="text-align:left;">69.2米</td></tr></tbody></table><h4 id="设计灵感" tabindex="-1">设计灵感 <a class="header-anchor" href="#设计灵感" aria-label="Permalink to &quot;设计灵感&quot;">​</a></h4><p>鸟巢的外观像一个巨大的鸟巢，由24根钢柱和大量钢结构编织而成。这种设计既体现了中国传统文化中&quot;天圆地方&quot;的理念，又具有现代建筑的前卫感。</p><h3 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to &quot;主要功能&quot;">​</a></h3><p>鸟巢不仅是体育场馆，还是大型演出、展览等活动的举办地。</p><h4 id="主要活动" tabindex="-1">主要活动 <a class="header-anchor" href="#主要活动" aria-label="Permalink to &quot;主要活动&quot;">​</a></h4><ul><li><strong>体育赛事</strong>：中超、亚冠等足球比赛</li><li><strong>演唱会</strong>：国内外知名歌手演唱会</li><li><strong>旅游参观</strong>：日常对外开放参观</li></ul><h2 id="水立方-国家游泳中心" tabindex="-1">水立方（国家游泳中心） <a class="header-anchor" href="#水立方-国家游泳中心" aria-label="Permalink to &quot;水立方（国家游泳中心）&quot;">​</a></h2><h3 id="建筑特色-1" tabindex="-1">建筑特色 <a class="header-anchor" href="#建筑特色-1" aria-label="Permalink to &quot;建筑特色&quot;">​</a></h3><p>水立方由澳大利亚PTW建筑事务所设计，外观像一池碧蓝的清水，由3000多个ETFE膜结构气泡组成。</p><h4 id="建筑参数-1" tabindex="-1">建筑参数 <a class="header-anchor" href="#建筑参数-1" aria-label="Permalink to &quot;建筑参数&quot;">​</a></h4><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">数据</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>占地面积</strong></td><td style="text-align:left;">6.29公顷</td></tr><tr><td style="text-align:left;"><strong>建筑面积</strong></td><td style="text-align:left;">8万平方米</td></tr><tr><td style="text-align:left;"><strong>座位数</strong></td><td style="text-align:left;">17000个</td></tr><tr><td style="text-align:left;"><strong>膜结构数量</strong></td><td style="text-align:left;">3607个</td></tr><tr><td style="text-align:left;"><strong>高度</strong></td><td style="text-align:left;">30米</td></tr></tbody></table><h4 id="设计灵感-1" tabindex="-1">设计灵感 <a class="header-anchor" href="#设计灵感-1" aria-label="Permalink to &quot;设计灵感&quot;">​</a></h4><p>水立方的设计灵感来源于&quot;水分子&quot;，外观由无数个&quot;气泡&quot;组成，象征着水的生命力和灵动性。</p><h3 id="主要功能-1" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能-1" aria-label="Permalink to &quot;主要功能&quot;">​</a></h3><p>水立方目前主要作为游泳馆和旅游观光点对外开放。</p><h4 id="主要设施" tabindex="-1">主要设施 <a class="header-anchor" href="#主要设施" aria-label="Permalink to &quot;主要设施&quot;">​</a></h4><ul><li><strong>比赛泳池</strong>：国际标准游泳池</li><li><strong>嬉水乐园</strong>：适合家庭游玩的水上乐园</li><li><strong>冰壶场地</strong>：冬季开放冰壶体验</li></ul><h2 id="奥林匹克公园" tabindex="-1">奥林匹克公园 <a class="header-anchor" href="#奥林匹克公园" aria-label="Permalink to &quot;奥林匹克公园&quot;">​</a></h2><h3 id="奥林匹克塔" tabindex="-1">奥林匹克塔 <a class="header-anchor" href="#奥林匹克塔" aria-label="Permalink to &quot;奥林匹克塔&quot;">​</a></h3><p>奥林匹克塔是北京的新地标，高246.8米，塔顶设有观景台，可以俯瞰整个奥林匹克公园。</p><h3 id="奥林匹克森林公园" tabindex="-1">奥林匹克森林公园 <a class="header-anchor" href="#奥林匹克森林公园" aria-label="Permalink to &quot;奥林匹克森林公园&quot;">​</a></h3><p>奥林匹克森林公园位于鸟巢和水立方的北侧，是北京最大的城市公园之一。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>精华路线（约2小时）</strong>：</p><p>地铁8号线奥体中心站 → 鸟巢外观 → 鸟巢内部参观 → 水立方外观 → 水立方内部参观 → 奥林匹克公园散步</p><p><strong>深度路线（约半天）</strong>：</p><p>上午：鸟巢 → 水立方 → 奥林匹克塔 下午：奥林匹克森林公园 → 奥林匹克公园 晚上：夜景灯光秀</p><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>最佳时间</strong>：傍晚时分和夜晚，灯光亮起后景色最美</li><li><strong>夜景拍摄</strong>：建议携带三脚架，夜景拍摄效果更佳</li><li><strong>门票购买</strong>：可以购买联票，更划算</li><li><strong>交通便利</strong>：地铁8号线直达，非常方便</li><li><strong>周边餐饮</strong>：奥林匹克公园周边有大量餐厅和购物中心</li></ol><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">路线</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>地铁</strong></td><td style="text-align:left;">8号线奥体中心站B1口</td></tr><tr><td style="text-align:left;"><strong>公交</strong></td><td style="text-align:left;">81、82、510、607路国家体育馆站</td></tr><tr><td style="text-align:left;"><strong>打车</strong></td><td style="text-align:left;">定位&quot;鸟巢&quot;或&quot;水立方&quot;即可</td></tr></tbody></table><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">奥林匹克森林公园</td><td style="text-align:center;">步行5分钟</td><td style="text-align:left;">城市绿肺</td></tr><tr><td style="text-align:left;">奥林匹克塔</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">北京新地标</td></tr><tr><td style="text-align:left;">中国科技馆</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">科普教育</td></tr><tr><td style="text-align:left;">国家会议中心</td><td style="text-align:center;">步行10分钟</td><td style="text-align:left;">国际会展中心</td></tr></tbody></table><h2 id="文化意义" tabindex="-1">文化意义 <a class="header-anchor" href="#文化意义" aria-label="Permalink to &quot;文化意义&quot;">​</a></h2><p>鸟巢和水立方是2008年北京奥运会的象征，也是中国改革开放成就的标志。它们不仅代表了中国的建筑水平，更代表了中国的国际形象。</p><p>&quot;同一个世界，同一个梦想&quot;，这句奥运口号在这里得到了最好的诠释。</p><hr><p><strong>📍 地址</strong>：北京市朝阳区国家体育场南路1号（鸟巢），天辰东路11号（水立方） <strong>🚇 地铁</strong>：8号线奥体中心站B1口 <strong>📞 电话</strong>：010-84373008（鸟巢），010-84373009（水立方） <strong>🌐 官网</strong>：<a href="http://www.n-s.cn" target="_blank" rel="noreferrer">www.n-s.cn</a>（鸟巢），<a href="http://www.watercube.com.cn" target="_blank" rel="noreferrer">www.watercube.com.cn</a>（水立方）</p><p><strong>💡 Tips</strong>：鸟巢和水立方的夜景非常壮观，建议傍晚前往，感受灯光下的建筑之美。</p>',52)])])}const c=e(n,[["render",o]]);export{f as __pageData,c as default};
